    settings_wshub_title: 'Widgets & sharing', settings_wshub_hint: 'Extend the dashboard or share your setup', settings_create_title: "Create",
    settings_create_lead: "Two paths: no-code in a minute, or code for full control.",
    settings_create_nocode_label: "No code — Widget Creator",
    settings_create_nocode_limits: "Fast and guided — but limited to the available templates. For something truly yours, go the code route.",
    settings_create_code_label: "With code — widget SDK",
    settings_create_code_lead: "Full control over looks and features: HTML/JS in a safe sandbox, with live dashboard data and actions approved by whoever installs it.",
    settings_create_code_step1: "Read the SDK guide: the API, the available data, complete examples.",
    settings_create_code_step2: "Build inside the server/data/widgets folder — the package shows up in the installed-widgets list below.",
