    settings_create_publish_guide: "Guidelines for publishing to the catalog →",
    settings_create_other_hint: "Everything else is created right in the app: themes and backgrounds in Appearance, pages in the layout editor, profiles on the Deck widget, Ambient scenes in Ambient mode.",
